/**
 * @summary Next upcoming appointments
 */
export const getGetUpcomingAppointmentsUrl = (
  params?: GetUpcomingAppointmentsParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/dashboard/upcoming?${stringifiedParams}`
    : `/api/dashboard/upcoming`;
};

export const getUpcomingAppointments = async (
  params?: GetUpcomingAppointmentsParams,
  options?: RequestInit,
): Promise<Appointment[]> => {
  return customFetch<Appointment[]>(getGetUpcomingAppointmentsUrl(params), {
    ...options,
    method: "GET",
  });
};

